import{_ as i,o as a,c as t,ae as o}from"./chunks/framework.DLnLGGYb.js";const g=JSON.parse('{"title":"项目分类","description":"","frontmatter":{},"headers":[],"relativePath":"categories.md","filePath":"categories.md"}'),e={name:"categories.md"};function r(s,l,n,u,h,c){return a(),t("div",null,[...l[0]||(l[0]=[o('<h1 id="项目分类" tabindex="-1">项目分类 <a class="header-anchor" href="#项目分类" aria-label="Permalink to &quot;项目分类&quot;">​</a></h1><h2 id="分类体系" tabindex="-1">分类体系 <a class="header-anchor" href="#分类体系" aria-label="Permalink to &quot;分类体系&quot;">​</a></h2><p>我们按照以下分类体系组织项目，确保每个项目都有明确的归属和收录标准。</p><h3 id="_1-智能前沿-ai-ml" tabindex="-1">1. 智能前沿 (AI &amp; ML) <a class="header-anchor" href="#_1-智能前沿-ai-ml" aria-label="Permalink to &quot;1. 智能前沿 (AI &amp; ML)&quot;">​</a></h3><p><strong>二级分类</strong>：</p><ul><li>LLM 框架</li><li>AI Agent</li><li>本地大模型 (Ollama/Local)</li><li>图像/视频生成</li></ul><p><strong>创新细节/收录侧重</strong>：</p><ul><li>侧重于&quot;一键运行&quot;和&quot;低门槛接入&quot;的项目</li><li>关注模型性能和易用性</li><li>优先收录有实际应用场景的项目</li></ul><h3 id="_2-开发利器-devtools" tabindex="-1">2. 开发利器 (DevTools) <a class="header-anchor" href="#_2-开发利器-devtools" aria-label="Permalink to &quot;2. 开发利器 (DevTools)&quot;">​</a></h3><p><strong>二级分类</strong>：</p><ul><li>终端增强 (CLI)</li><li>API 工具</li><li>高效 IDE 插件</li><li>测试/调试</li></ul><p><strong>创新细节/收录侧重</strong>：</p><ul><li>标注&quot;提升效率百分比&quot;，强调对工作流的改造</li><li>关注工具的稳定性和可靠性</li><li>优先收录能够解决实际开发痛点的项目</li></ul><h3 id="_3-现代-web-web-stack" tabindex="-1">3. 现代 Web (Web Stack) <a class="header-anchor" href="#_3-现代-web-web-stack" aria-label="Permalink to &quot;3. 现代 Web (Web Stack)&quot;">​</a></h3><p><strong>二级分类</strong>：</p><ul><li>全栈框架</li><li>UI 组件库</li><li>低代码 (Low-code)</li><li>动效/可视化</li></ul><p><strong>创新细节/收录侧重</strong>：</p><ul><li>增加&quot;性能评分&quot;和&quot;设计风格&quot;标签（如：Bento, Minimal）</li><li>关注用户体验和开发效率</li><li>优先收录有创新性设计的项目</li></ul><h3 id="_4-基础设施-infra" tabindex="-1">4. 基础设施 (Infra) <a class="header-anchor" href="#_4-基础设施-infra" aria-label="Permalink to &quot;4. 基础设施 (Infra)&quot;">​</a></h3><p><strong>二级分类</strong>：</p><ul><li>Docker/K8s 工具</li><li>数据库/存储</li><li>安全/防护</li><li>网络/穿透</li></ul><p><strong>创新细节/收录侧重</strong>：</p><ul><li>侧重于&quot;高可用&quot;和&quot;轻量化&quot;替代方案</li><li>关注系统的稳定性和安全性</li><li>优先收录能够简化基础设施管理的项目</li></ul><h3 id="_5-自托管-self-hosted" tabindex="-1">5. 自托管 (Self-Hosted) <a class="header-anchor" href="#_5-自托管-self-hosted" aria-label="Permalink to &quot;5. 自托管 (Self-Hosted)&quot;">​</a></h3><p><strong>二级分类</strong>：</p><ul><li>云服务替代品</li><li>家庭实验室 (NAS)</li><li>私人影音</li><li>自动化流</li></ul><p><strong>创新细节/收录侧重</strong>：</p><ul><li>核心卖点：隐私保护、数据自主、部署成本</li><li>关注项目的可维护性和扩展性</li><li>优先收录适合个人和小团队使用的项目</li></ul><h3 id="_6-终身学习-resources" tabindex="-1">6. 终身学习 (Resources) <a class="header-anchor" href="#_6-终身学习-resources" aria-label="Permalink to &quot;6. 终身学习 (Resources)&quot;">​</a></h3><p><strong>二级分类</strong>：</p><ul><li>技术路线图 (Roadmap)</li><li>电子书合集</li><li>面试/算法</li><li>优质论文</li></ul><p><strong>创新细节/收录侧重</strong>：</p><ul><li>剔除单纯的链接堆砌，只收录&quot;系统性&quot;的项目</li><li>关注内容的质量和实用性</li><li>优先收录有结构化内容的项目</li></ul><h2 id="gitfame-分类" tabindex="-1">GitFame 分类 <a class="header-anchor" href="#gitfame-分类" aria-label="Permalink to &quot;GitFame 分类&quot;">​</a></h2><ul><li><strong>一级分类</strong>：开发利器 (DevTools)</li><li><strong>二级分类</strong>：终端增强 (CLI)</li><li><strong>收录侧重</strong>：提升效率百分比，强调对工作流的改造</li><li><strong>效率提升</strong>：相比手动分析，提升效率达 95% 以上</li></ul>',35)])])}const p=i(e,[["render",r]]);export{g as __pageData,p as default};
